$data = Get-Content "$env:temp\winsat_res.txt"; $read = ($data | Select-String 'Disk\s+Sequential\s+64.0\s+Read' | ForEach-Object { ($_ -split '\s+')[4..5] -join ' ' }); $write = ($data | Select-String 'Disk\s+Sequential\s+64.0\s+Write' | ForEach-Object { ($_ -split '\s+')[4..5] -join ' ' }); Write-Host 'Seka skaitymas: ' -NoNewline; if ($read) { Write-Host $read -ForegroundColor Green } else { Write-Host 'Nenustatyta' -ForegroundColor Red }; Write-Host 'Seka rasymas:   ' -NoNewline; if ($write) { Write-Host $write -ForegroundColor Cyan } else { Write-Host 'Nenustatyta' -ForegroundColor Red }
